import styles from "./nav-list.module.css";

const NavList: React.FC = () => {
  return (
    <>
    <div className={styles.divider}/>
    <ul className={styles.list_items}>
      <li>
        <a href="/somepage" className={styles.item}>
          New season
        </a>
      </li>
      <li>
        <a href="/somepage" className={styles.item}>
          Most searched
        </a>
      </li>
      <li>
        <a href="/somepage" className={styles.item}>
          Most selled
        </a>
      </li>
    </ul>
    </>

  );
};

export default NavList;

